// Track server startup time for uptime calculation
let startTime: number;

export function initializeUptime(): void {
  startTime = Date.now();
}

export function getUptimeSeconds(): number {
  if (!startTime) {
    return 0;
  }
  return Math.floor((Date.now() - startTime) / 1000);
}

import { readFileSync } from 'fs';
import { join } from 'path';

let cachedVersion: string;

function loadVersion(): string {
  try {
    const packageJsonPath = join(process.cwd(), 'package.json');
    const packageJson = JSON.parse(readFileSync(packageJsonPath, 'utf-8'));
    return packageJson.version || 'unknown';
  } catch (error) {
    console.warn('Failed to read version from package.json:', error);
    return 'unknown';
  }
}

export function getVersion(): string {
  if (!cachedVersion) {
    cachedVersion = loadVersion();
  }
  return cachedVersion;
}

import { getAvailableModels } from '~/lib/model-mapping';

export function getModelCount(): number {
  try {
    const models = getAvailableModels();
    if (Array.isArray(models)) {
      return models.length;
    }
    if (typeof models === 'object' && models !== null) {
      return Object.keys(models).length;
    }
    return 0;
  } catch (error) {
    console.warn('Failed to get model count:', error);
    return 0;
  }
}

import { Request, Response } from 'express';
import { getUptimeSeconds } from '~/lib/uptime';
import { getVersion } from '~/lib/version';
import { getModelCount } from '~/lib/model-counter';

export async function healthHandler(
  req: Request,
  res: Response
): Promise<void> {
  const response = {
    uptime: getUptimeSeconds(),
    modelCount: getModelCount(),
    version: getVersion(),
  };

  res.status(200).json(response);
}

import { describe, it, expect, beforeEach } from 'vitest';
import { getUptimeSeconds, initializeUptime } from '~/lib/uptime';
import { getVersion } from '~/lib/version';
import { getModelCount } from '~/lib/model-counter';

describe('Health Module', () => {
  describe('uptime', () => {
    beforeEach(() => {
      initializeUptime();
    });

    it('should return numeric uptime in seconds', () => {
      const uptime = getUptimeSeconds();
      expect(typeof uptime).toBe('number');
      expect(uptime).toBeGreaterThanOrEqual(0);
    });

    it('uptime should increase between calls', async () => {
      const uptime1 = getUptimeSeconds();
      await new Promise(resolve => setTimeout(resolve, 100));
      const uptime2 = getUptimeSeconds();
      expect(uptime2).toBeGreaterThanOrEqual(uptime1);
    });
  });

  describe('version', () => {
    it('should return a non-empty string', () => {
      const version = getVersion();
      expect(typeof version).toBe('string');
      expect(version.length).toBeGreaterThan(0);
    });

    it('should cache version after first call', () => {
      const version1 = getVersion();
      const version2 = getVersion();
      expect(version1).toBe(version2);
    });
  });

  describe('model counter', () => {
    it('should return non-negative integer', () => {
      const count = getModelCount();
      expect(Number.isInteger(count)).toBe(true);
      expect(count).toBeGreaterThanOrEqual(0);
    });
  });
});

import { describe, it, expect } from 'vitest';
import request from 'supertest';
import { app } from '~/server';

describe('GET /health', () => {
  it('should return 200 status', async () => {
    const response = await request(app).get('/health');
    expect(response.status).toBe(200);
  });

  it('should return JSON with correct content-type', async () => {
    const response = await request(app).get('/health');
    expect(response.type).toMatch(/json/);
  });

  it('should include uptime, modelCount, and version fields', async () => {
    const response = await request(app).get('/health');
    expect(response.body).toHaveProperty('uptime');
    expect(response.body).toHaveProperty('modelCount');
    expect(response.body).toHaveProperty('version');
  });

  it('should have correct field types', async () => {
    const response = await request(app).get('/health');
    expect(typeof response.body.uptime).toBe('number');
    expect(typeof response.body.modelCount).toBe('number');
    expect(typeof response.body.version).toBe('string');
  });

  it('uptime should increase on subsequent requests', async () => {
    const response1 = await request(app).get('/health');
    await new Promise(resolve => setTimeout(resolve, 100));
    const response2 = await request(app).get('/health');
    expect(response2.body.uptime).toBeGreaterThanOrEqual(response1.body.uptime);
  });
});

